<style>#article-container .banner .container{z-index:2}#article-container .banner .bg-left{bottom:0;left:0;width:100px;height:130px}#article-container .banner .bg-right{right:0;width:100px;height:130px;-webkit-transform:scale(-1,1);-moz-transform:scale(-1,1);-ms-transform:scale(-1,1);transform:scale(-1,1)}#article-container .banner .breadcrumbs{margin-top:20px}#article-container #articleBody{display:-webkit-box;display:-webkit-flex;display:-moz-box;display:-ms-flexbox;display:flex;-webkit-box-align:start;-webkit-align-items:flex-start;-moz-box-align:start;-ms-flex-align:start;align-items:flex-start;-webkit-box-pack:justify;-webkit-justify-content:space-between;-moz-box-pack:justify;-ms-flex-pack:justify;justify-content:space-between;margin-bottom:100px}#article-container #articleBody .articleBody{width:65%}#article-container #articleBody .articleBody .articleFeatured{text-align:center}#article-container #articleBody .articleBody .articleFeatured img{max-height:450px;max-width:100%}#article-container #articleBody .articleBody .articleDetails{margin-top:20px;display:-webkit-box;display:-webkit-flex;display:-moz-box;display:-ms-flexbox;display:flex;-webkit-box-align:center;-webkit-align-items:center;-moz-box-align:center;-ms-flex-align:center;align-items:center;-webkit-box-pack:justify;-webkit-justify-content:space-between;-moz-box-pack:justify;-ms-flex-pack:justify;justify-content:space-between}#article-container #articleBody .articleBody .articleDetails .article-date{color:#23529e;font-size:20px}#article-container #articleBody .articleBody .articleDetails .article-category{color:#819499;border-radius:6px;border:1px solid #819499;padding:5px 8px;background:#ec1d293b;font-size:12px;text-transform:uppercase}#article-container #articleBody .articleBody .articleContent{color:#819499;font-family:'DM Sans';font-size:20px;line-height:32px}#article-container #articleBody #articleSidebar{position:-webkit-sticky;position:sticky;top:100px;width:30%}#article-container #articleBody #latestPosts{padding:20px;border-radius:10px;border:2px solid #f6f6f6;-webkit-box-shadow:0 4px 20.1px -7px rgba(0,0,0,.02);box-shadow:0 4px 20.1px -7px rgba(0,0,0,.02)}#article-container #articleBody #latestPosts .latest-post-header{color:#23529e;font-weight:700;font-size:24px;font-family:'Exo 2'}#article-container #articleBody #latestPosts .latest-post-items a{text-decoration:none}#article-container #articleBody #latestPosts .latest-post-item{padding:15px 0;border-bottom:2px solid #f0f0f0;display:-webkit-box;display:-webkit-flex;display:-moz-box;display:-ms-flexbox;display:flex;gap:10px;-webkit-box-align:stretch;-webkit-align-items:stretch;-moz-box-align:stretch;-ms-flex-align:stretch;align-items:stretch;-webkit-box-pack:start;-webkit-justify-content:flex-start;-moz-box-pack:start;-ms-flex-pack:start;justify-content:flex-start}#article-container #articleBody #latestPosts .latest-post-item:last-child{border-bottom:0;padding-bottom:0}#article-container #articleBody #latestPosts .latest-post-item .latest-post-img{border-radius:5px;width:35%}#article-container #articleBody #latestPosts .latest-post-item .latest-post-details{width:65%}#article-container #articleBody #latestPosts .latest-post-item .latest-post-details .latest-post-title{color:#6a7375;font-weight:600;font-family:'Exo 2';line-height:1.2;font-size:18px;max-height:77px}#article-container #articleBody #latestPosts .latest-post-item .latest-post-details .latest-post-date{margin-top:10px;color:#819499;font-size:16px;font-weight:400}@media (max-width:767px){#article-container #articleBody{-webkit-flex-wrap:wrap;-ms-flex-wrap:wrap;flex-wrap:wrap}#article-container #articleBody .articleBody{width:100%}#article-container #articleBody .articleBody .articleContent{font-size:16px;line-height:27px}#article-container #articleBody .articleBody .articleContent img{max-width:100%}#article-container #articleBody #articleSidebar{width:100%}}</style>